css:
* { margin: 0; padding: 0; box-sizing: border-box; }
body { font-family: -apple-system, BlinkMacSystemFont, 'Segoe UI', sans-serif; background: #f0f4f8; color: #1a202c; }
nav { display: flex; align-items: center; justify-content: space-between; padding: 0 32px; height: 64px; background: #0f172a; position: sticky; top: 0; z-index: 100; }
.logo { font-size: 20px; font-weight: 800; color: white; }
.search { display: flex; align-items: center; gap: 10px; background: rgba(255,255,255,0.1); border-radius: 24px; padding: 10px 18px; width: 420px; } .search input { border: none; background: transparent; color: white; outline: none; width: 100%; font-size: 14px; } .search input::placeholder { color: rgba(255,255,255,0.4); } .search span { color: rgba(255,255,255,0.5); }
.nav-right { display: flex; align-items: center; gap: 16px; }
.nav-icon { font-size: 22px; cursor: pointer; }
.cart-wrap { position: relative; cursor: pointer; font-size: 22px; } .cart-badge { position: absolute; top: -6px; right: -6px; width: 18px; height: 18px; border-radius: 50%; background: #3b82f6; color: white; font-size: 10px; font-weight: 800; display: flex; align-items: center; justify-content: center; }
.hero-banner { display: flex; justify-content: space-between; align-items: center; padding: 40px 48px; background: linear-gradient(135deg, #0f172a, #1e3a5f); color: white; }
.banner-tag { display: inline-block; background: #ef4444; color: white; padding: 4px 12px; border-radius: 20px; font-size: 12px; font-weight: 800; margin-bottom: 12px; }
.banner-content h2 { font-size: 48px; font-weight: 900; margin-bottom: 10px; } .banner-content p { font-size: 18px; color: rgba(255,255,255,0.7); margin-bottom: 24px; } .banner-content p strong { color: #60a5fa; font-size: 22px; }
.banner-btn { padding: 14px 32px; border-radius: 12px; border: none; background: #3b82f6; color: white; font-weight: 800; font-size: 16px; cursor: pointer; }
.banner-emoji { font-size: 120px; }
.categories-bar { display: flex; gap: 8px; padding: 16px 32px; background: white; border-bottom: 1px solid #e2e8f0; overflow-x: auto; }
.cb { padding: 10px 20px; border-radius: 20px; border: 1px solid #e2e8f0; background: transparent; color: #6b7280; font-size: 14px; font-weight: 600; cursor: pointer; white-space: nowrap; transition: all 0.2s; } .cb.active { background: #0f172a; border-color: #0f172a; color: white; }
.products-area { padding: 24px 32px; }
.products-grid { display: grid; grid-template-columns: repeat(auto-fill, minmax(220px, 1fr)); gap: 16px; }
.product-card { background: white; border-radius: 16px; overflow: hidden; border: 1px solid #e2e8f0; transition: all 0.2s; cursor: pointer; } .product-card:hover { transform: translateY(-4px); box-shadow: 0 12px 32px rgba(0,0,0,0.1); }
.pc-badge { position: absolute; top: 10px; left: 10px; background: #ef4444; color: white; padding: 3px 8px; border-radius: 6px; font-size: 11px; font-weight: 800; }
.pc-img-wrap { position: relative; height: 180px; background: #f8fafc; display: flex; align-items: center; justify-content: center; font-size: 72px; }
.pc-info { padding: 14px; }
.pc-brand { font-size: 11px; font-weight: 700; color: #3b82f6; letter-spacing: 1px; margin-bottom: 4px; }
.pc-name { font-size: 14px; font-weight: 700; margin-bottom: 8px; line-height: 1.3; color: #1a202c; }
.pc-price-row { display: flex; justify-content: space-between; align-items: center; }
.pc-price { font-size: 18px; font-weight: 900; color: #1a202c; }
.pc-old { font-size: 12px; color: #9ca3af; text-decoration: line-through; margin-left: 4px; }
.add-cart { width: 36px; height: 36px; border-radius: 50%; border: none; background: #3b82f6; color: white; font-size: 18px; cursor: pointer; display: flex; align-items: center; justify-content: center; flex-shrink: 0; }
.cart-drawer { position: fixed; right: -380px; top: 0; width: 380px; height: 100vh; background: white; z-index: 200; transition: right 0.3s; display: flex; flex-direction: column; box-shadow: -4px 0 20px rgba(0,0,0,0.1); }
.cart-drawer.open { right: 0; }
.overlay { position: fixed; inset: 0; background: rgba(0,0,0,0.5); z-index: 199; display: none; } .overlay.open { display: block; }
.drawer-header { display: flex; justify-content: space-between; align-items: center; padding: 20px; border-bottom: 1px solid #e2e8f0; } .drawer-header h3 { font-size: 18px; font-weight: 800; color: #1a202c; } .drawer-header button { width: 32px; height: 32px; border-radius: 50%; border: none; background: #f1f5f9; cursor: pointer; font-size: 16px; }
.drawer-items { flex: 1; overflow-y: auto; padding: 16px; }
.di-item { display: flex; gap: 12px; align-items: center; padding: 12px 0; border-bottom: 1px solid #f1f5f9; }
.di-emoji { font-size: 36px; width: 48px; text-align: center; }
.di-info { flex: 1; } .di-info strong { display: block; font-size: 14px; color: #1a202c; margin-bottom: 2px; } .di-info span { color: #3b82f6; font-weight: 700; }
.di-remove { background: none; border: none; color: #ef4444; cursor: pointer; font-size: 18px; }
.drawer-footer { padding: 16px; border-top: 1px solid #e2e8f0; }
.drawer-total { display: flex; justify-content: space-between; align-items: center; margin-bottom: 14px; font-size: 16px; color: #1a202c; } .drawer-total strong { font-size: 22px; font-weight: 900; }
.checkout-btn { width: 100%; height: 50px; border-radius: 14px; border: none; background: #0f172a; color: white; font-size: 16px; font-weight: 800; cursor: pointer; }

