const products = [
  {id:1,name:'iPhone 15 Pro',brand:'APPLE',price:39999,old:44999,cat:'telefon',emoji:'📱',badge:'%11 İNDİRİM'},
  {id:2,name:'MacBook Air M2',brand:'APPLE',price:38999,cat:'bilgisayar',emoji:'💻'},
  {id:3,name:'Samsung Galaxy S24',brand:'SAMSUNG',price:32999,cat:'telefon',emoji:'📲'},
  {id:4,name:'iPad Pro 12.9"',brand:'APPLE',price:28999,cat:'tablet',emoji:'📱'},
  {id:5,name:'AirPods Pro 2',brand:'APPLE',price:8499,old:9999,cat:'aksesuar',emoji:'🎧',badge:'%15 İNDİRİM'},
  {id:6,name:'Sony WH-1000XM5',brand:'SONY',price:6999,cat:'aksesuar',emoji:'🎧'},
  {id:7,name:'LG OLED 55"',brand:'LG',price:42999,cat:'tv',emoji:'📺'},
  {id:8,name:'Dell XPS 15',brand:'DELL',price:45999,cat:'bilgisayar',emoji:'💻'}
];
let cart = [], currentCat = 'all';
function renderProducts() {
  const visible = currentCat === 'all' ? products : products.filter(p => p.cat === currentCat);
  document.getElementById('grid').innerHTML = visible.map(p => `
    <div class='product-card'>
      <div class='pc-img-wrap'>${p.badge ? `<div class='pc-badge'>${p.badge}</div>` : ''}${p.emoji}</div>
      <div class='pc-info'>
        <div class='pc-brand'>${p.brand}</div>
        <div class='pc-name'>${p.name}</div>
        <div class='pc-price-row'>
          <div><span class='pc-price'>₺${p.price.toLocaleString('tr')}</span>${p.old ? `<span class='pc-old'>₺${p.old.toLocaleString('tr')}</span>` : ''}</div>
          <button class='add-cart' onclick='addCart(${p.id})'>+</button>
        </div>
      </div>
    </div>
  `).join('');
}
function addCart(id) {
  const p = products.find(p => p.id === id);
  const ex = cart.find(c => c.id === id);
  if (ex) ex.qty++; else cart.push({...p, qty: 1});
  updateCart();
}
function removeCart(id) { cart = cart.filter(c => c.id !== id); updateCart(); }
function updateCart() {
  document.getElementById('badge').textContent = cart.reduce((s,c)=>s+c.qty,0);
  const total = cart.reduce((s,c)=>s+c.price*c.qty,0);
  document.getElementById('total').textContent = '₺' + total.toLocaleString('tr');
  document.getElementById('drawer-items').innerHTML = cart.length === 0 ? '<p style="text-align:center;color:#9ca3af;padding:40px">Sepetiniz boş</p>' : cart.map(c => `<div class='di-item'><span class='di-emoji'>${c.emoji}</span><div class='di-info'><strong>${c.name} x${c.qty}</strong><span>₺${(c.price*c.qty).toLocaleString('tr')}</span></div><button class='di-remove' onclick='removeCart(${c.id})'>×</button></div>`).join('');
}
function toggleCart() { document.getElementById('drawer').classList.toggle('open'); document.getElementById('overlay').classList.toggle('open'); }
function cat(c, btn) { currentCat = c; document.querySelectorAll('.cb').forEach(b => b.classList.remove('active')); btn.classList.add('active'); renderProducts(); }
renderProducts();
